import Vue from 'vue'
import 'vue-tsx-support/enable-check'
import App from './App'
import store from './store'
import { calculateWindow2, initAppleLogin, loadVConsoleIfNeed } from './utils/func'
import { initErrorHandler } from './utils/event'
import { initWebSa, reportWebSa } from './utils/report'
import { getConfigAndDial } from './utils/dial'
import FirebaseManager from './utils/firebase-manager'

Vue.config.productionTip = false

export const initBloot = async () => {
  await FirebaseManager.getInstance().init()
  await getConfigAndDial()
  // reportWebSa('h5_loginpage_baloot_cancellation_pop_show_test', {
  //   type: 'baloot授权登录test',
  //   Baloot_uid: '-1'
  // })

  initAppleLogin()

  initErrorHandler()

  calculateWindow2()

  loadVConsoleIfNeed()

  new Vue({
    store,
    render: (h) => h(App),
  }).$mount('#app')
}
